// ------------------------------------------------------------------
//  Design Unit:    Top_Interrupt_run_interrupt_run_interrupt_fsm
//  FSM Module
// ------------------------------------------------------------------


module Top_Interrupt_run_interrupt_run_interrupt_fsm (
  clk, rst, IRQ_trigger_Pop_mioi_wen_comp, fsm_output, while_for_C_0_tr0
);
  input clk;
  input rst;
  input IRQ_trigger_Pop_mioi_wen_comp;
  output [2:0] fsm_output;
  reg [2:0] fsm_output;
  input while_for_C_0_tr0;


  // FSM State Type Declaration for Top_Interrupt_run_interrupt_run_interrupt_fsm_1
  parameter
    run_interrupt_rlp_C_0 = 3'd0,
    while_C_0 = 3'd1,
    while_C_1 = 3'd2,
    while_for_C_0 = 3'd3,
    while_C_2 = 3'd4;

  reg [2:0] state_var;
  reg [2:0] state_var_NS;


  // Interconnect Declarations for Component Instantiations 
  always @(*)
  begin : Top_Interrupt_run_interrupt_run_interrupt_fsm_1
    case (state_var)
      while_C_0 : begin
        fsm_output = 3'b001;
        state_var_NS = while_C_1;
      end
      while_C_1 : begin
        fsm_output = 3'b010;
        state_var_NS = while_for_C_0;
      end
      while_for_C_0 : begin
        fsm_output = 3'b011;
        if ( while_for_C_0_tr0 ) begin
          state_var_NS = while_C_2;
        end
        else begin
          state_var_NS = while_for_C_0;
        end
      end
      while_C_2 : begin
        fsm_output = 3'b100;
        state_var_NS = while_C_0;
      end
      // run_interrupt_rlp_C_0
      default : begin
        fsm_output = 3'b000;
        state_var_NS = while_C_0;
      end
    endcase
  end

  always @(posedge clk or negedge rst) begin
    if ( ~ rst ) begin
      state_var <= run_interrupt_rlp_C_0;
    end
    else if ( IRQ_trigger_Pop_mioi_wen_comp ) begin
      state_var <= state_var_NS;
    end
  end

endmodule

